// IcpmsAssignmentStats is the resolver for the icpmsAssignmentStats field.
func (r *queryResolver) IcpmsAssignmentStats(ctx context.Context, organizationID gid.GID) (*types.IcpmsAssignmentStats, error) {
	scope := coredata.NewScopeFromObjectID(organizationID)
	items, err := r.probo.IcpmsAssignments.ListForOrganization(ctx, scope, organizationID)
	if err != nil {
		return nil, fmt.Errorf("cannot compute assignment stats: %w", err)
	}

	stats := &types.IcpmsAssignmentStats{}
	now := time.Now()
	for _, item := range items {
		stats.TotalAssignments++
		isOverdue := item.DueDate != nil && item.DueDate.Before(now) &&
			item.Status != coredata.IcpmsAssignmentStatusCompleted &&
			item.Status != coredata.IcpmsAssignmentStatusClosed &&
			item.Status != coredata.IcpmsAssignmentStatusCancelled
		switch item.Status {
		case coredata.IcpmsAssignmentStatusAssigned:
			stats.Assigned++
		case coredata.IcpmsAssignmentStatusAccepted:
			stats.Accepted++
		case coredata.IcpmsAssignmentStatusInProgress:
			stats.InProgress++
		case coredata.IcpmsAssignmentStatusSubmitted:
			stats.Submitted++
		case coredata.IcpmsAssignmentStatusCompleted:
			stats.Completed++
		case coredata.IcpmsAssignmentStatusClosed:
			stats.Closed++
		case coredata.IcpmsAssignmentStatusCancelled:
			stats.Cancelled++
		}
		if isOverdue {
			stats.Overdue++
		}
	}
	return stats, nil
}

